mapper.update:
UPDATE onboarding_application
real_name = #{realName}, phone = #{phone, typeHandler=com.hrms.crypto.EncryptedStringTypeHandler}, phone_hash = #{phoneHash}, email = #{email, typeHandler=com.hrms.crypto.EncryptedStringTypeHandler}, id_card = #{idCard, typeHandler=com.hrms.crypto.EncryptedStringTypeHandler}, id_card_hash = #{idCardHash}, gender = #{gender}, registered_address = #{registeredAddress, typeHandler=com.hrms.crypto.EncryptedStringTypeHandler}, current_address = #{currentAddress, typeHandler=com.hrms.crypto.EncryptedStringTypeHandler}, target_dept_id = #{targetDeptId}, target_position_id = #{targetPositionId}, offer_salary = #{offerSalary, typeHandler=com.hrms.crypto.EncryptedBigDecimalTypeHandler}, probation_months = #{probationMonths}, entry_date = #{entryDate}, status = #{status}, employee_id = #{employeeId},
WHERE id = #{id}

mapper.select:
SELECT oa.id, oa.real_name, oa.phone, oa.email, oa.id_card, oa.target_dept_id, d.dept_name AS target_dept_name, oa.target_position_id, p.position_name AS target_position_name, oa.offer_salary, oa.probation_months, oa.entry_date, oa.status, oa.employee_id, oa.submitter_id, su.username AS submitter_name, oa.create_time, oa.update_time FROM onboarding_application oa LEFT JOIN department d ON oa.target_dept_id = d.id LEFT JOIN position p ON oa.target_position_id = p.id LEFT JOIN sys_user su ON oa.submitter_id = su.id
AND oa.status = #{status}
AND (oa.real_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY oa.create_time DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM onboarding_application oa

    AND oa.status = #{status}

        AND oa.real_name LIKE CONCAT('%', #{keyword}, '%')
